import os, base64

FILES = {
    'config.py': '',
    'main.py': '',
    'weekly_digest.py': '',
    'setup.sh': '',
    'requirements.txt': 'cmVxdWVzdHM+PTIuMzEuMApiZWF1dGlmdWxzb3VwND49NC4xMi4wCmZlZWRwYXJzZXI+PTYuMC4xMApseG1sPj00LjkuMAo=',
    'README.md': '',
    '.gitignore': '',
    'data/seen.json': 'ewogICJ0ZXN0X3h5el8wMDEiOiB7CiAgICAiZmlyc3Rfc2VlbiI6ICIyMDI2LTAzLTE2VDE3OjQ4OjA3LjQyODI0NCIKICB9Cn0=',
    'scrapers/__init__.py': 'IyBzY3JhcGVycyBwYWNrYWdlCg==',
    'scrapers/airdrop_scraper.py': '',
    'scrapers/coingecko_scraper.py': '',
    'scrapers/defillama_scraper.py': '',
    'scrapers/github_scraper.py': '',
    'scrapers/news_scraper.py': '',
    'scrapers/twitter_scraper.py': '',
    'scrapers/web3_jobs_scraper.py': '',
    'utils/__init__.py': 'IyB1dGlscyBwYWNrYWdlCg==',
    'utils/dedup.py': '',
    'utils/scorer.py': '',
    'utils/telegram_notifier.py': '',
    '.github/workflows/scraper.yml': '',
    '.github/workflows/weekly_digest.yml': '',
}

def main():
    created = []
    for rel_path, b64_content in FILES.items():
        # Create parent directories if needed
        dir_name = os.path.dirname(rel_path)
        if dir_name:
            os.makedirs(dir_name, exist_ok=True)
        # Write file
        with open(rel_path, "wb") as f:
            f.write(base64.b64decode(b64_content))
        created.append(rel_path)
        print(f"  ✅ {rel_path}")
    print(f"")
    print(f"✅ Created {len(created)} files.")
    print(f"")
    print("Next steps:")
    print("  1. Set GitHub Secrets (TELEGRAM_BOT_TOKEN, TELEGRAM_CHAT_ID, GH_PAT)")
    print("  2. git add . && git commit -m \"init: web3 alpha scraper\" && git push")
    print("  3. Go to Actions tab in GitHub → workflow will auto-run every 4h")

if __name__ == "__main__":
    print("🚀 Web3 Alpha Scraper — bootstrapping project files...")
    print()
    main()